-- Turkish Phone System - Client Side\nlocal QBCore = exports['qb-core']:GetCoreObject()\n\nlocal PhoneActive = false\nlocal PhoneContacts = {\n    {name = 'Polis', number = '911'},\n    {name = 'Ambulans', number = '112'},\n    {name = 'Itfaiye', number = '110'},\n    {name = 'Taksi', number = '8000'},\n}\n\nRegisterCommand('phone', function(source, args, rawCommand)\n    PhoneActive = not PhoneActive\n    if PhoneActive then\n        TriggerEvent('chat:addMessage', {args = {'Telefon', 'Telefon acildi. /call <numara>'}})\n    else\n        TriggerEvent('chat:addMessage', {args = {'Telefon', 'Telefon kapildi.'}})\n    end\nend, false)\n\nRegisterCommand('call', function(source, args, rawCommand)\n    if not PhoneActive then\n        TriggerEvent('chat:addMessage', {args = {'Telefon', 'Once telefonu aciniz!'}})\n        return\n    end\n    local number = args[1]\n    TriggerServerEvent('phone:call', number)\n    TriggerEvent('chat:addMessage', {args = {'Telefon', number .. ' aranıyor...'}})\nend, false)\n\nprint('^2[Turkish Phone System] Yuklendi!^7')"